public int fibonacci(int n) {
    int[] memo = new int[n + 1];
    for (int i = 0; i <= n; i++) {
        memo[i] = -1;
    }
    return fibonacci(n, memo);
}

private int fibonacci(int n, int[] memo) {
    if (n == 0 || n == 1) {
        return n;
    } else if (memo[n] != -1) {
        return memo[n];
    } else {
        int result = fibonacci(n - 1, memo) + fibonacci(n - 2, memo);
        memo[n] = result;
        return result;
    }
}

